dslRule:
/*!id: jdt.internal.typebinding.add.intersectioncasttype.condition*/
/*!description: Extends a boolean condition in TypeBinding to include 'isIntersectionCastType()' when handling new Java 8 intersection types.*/
/*!severity: info*/
isAnonymous() || this.binding.isLocalType() :: sourceVersionGE(8) && inClass("org.eclipse.jdt.core.dom.TypeBinding")
=> isAnonymous() || this.binding.isLocalType() || this.binding.isIntersectionCastType()
;;

@id: jdt.internal.creationreference.expression-property-to-type-property
@severity: info
org.eclipse.jdt.core.dom.CreationReference.EXPRESSION_PROPERTY :: sourceVersionGE(8)
=> org.eclipse.jdt.core.dom.CreationReference.TYPE_PROPERTY
;;

@id: jdt.internal.creationreference.getexpression-to-gettype
@severity: info
org.eclipse.jdt.core.dom.CreationReference.$node.getExpression() :: sourceVersionGE(8)
=> org.eclipse.jdt.core.dom.CreationReference.$node.getType()
;;

@id: jdt.internal.typemethodreference.clone-reorder-name-type
@severity: info
result.setName((org.eclipse.jdt.core.dom.SimpleName) getName().clone($target));
result.setType((org.eclipse.jdt.core.dom.Type) org.eclipse.jdt.core.dom.ASTNode.copySubtree($target, getType()));
=> result.setType((org.eclipse.jdt.core.dom.Type) org.eclipse.jdt.core.dom.ASTNode.copySubtree($target, getType()));
result.setName((org.eclipse.jdt.core.dom.SimpleName) getName().clone($target));
;;
